using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes back the input message with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Returns the server's current UTC time.")]
    public static string GetServerTime()
    {
        return DateTime.UtcNow.ToString("O");
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the application's current configuration settings.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new
            {
                EnableCaching = true,
                EnableLogging = true
            }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/version",
        Name = "App Version",
        MimeType = "application/json"),
     Description("Returns the server version and runtime information.")]
    public static string GetVersionInfo()
    {
        var info = new
        {
            Version = "1.0.0",
            Runtime = Environment.Version.ToString(),
            OS = Environment.OSVersion.ToString()
        };

        return JsonSerializer.Serialize(info, new JsonSerializerOptions { WriteIndented = true });
    }
}

